      window.scrollTo(0, 0);
      const verify = await verifyCaptcha(captchaToken);
      captchaRef.current?.reset();

      if (verify) {
        const registerationSuccess = await registerUser(formValue);
        setFormValue({
          email: "",
          fullname: "",
          password: "",
